import{_ as t,o as e,c as l,ag as o}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"菲尔·利切（Phil Lies）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/菲尔·利切.md","filePath":"04_people/菲尔·利切.md"}'),r={name:"04_people/菲尔·利切.md"};function i(h,a,d,n,u,s){return e(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="菲尔·利切-phil-lies" tabindex="-1">菲尔·利切（Phil Lies） <a class="header-anchor" href="#菲尔·利切-phil-lies" aria-label="Permalink to &quot;菲尔·利切（Phil Lies）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>Phil Lies</td></tr><tr><td>公司</td><td><a href="./../03_公司库/国家赔偿公司">国家赔偿公司</a></td></tr><tr><td>职位</td><td>总裁（退休前任）</td></tr><tr><td>退休年份</td><td>1982年（65岁）</td></tr></tbody></table><h2 id="职业生涯" tabindex="-1">职业生涯 <a class="header-anchor" href="#职业生涯" aria-label="Permalink to &quot;职业生涯&quot;">​</a></h2><h3 id="国家赔偿公司" tabindex="-1">国家赔偿公司 <a class="header-anchor" href="#国家赔偿公司" aria-label="Permalink to &quot;国家赔偿公司&quot;">​</a></h3><ul><li>伯克希尔保险业务核心子公司</li><li>与杰克·林格沃特（Jack Ringwalt）共同建立公司承保文化</li><li>1970年代至1982年管理公司</li></ul><h3 id="管理特点" tabindex="-1">管理特点 <a class="header-anchor" href="#管理特点" aria-label="Permalink to &quot;管理特点&quot;">​</a></h3><ol><li><strong>承保纪律严格</strong>：只做划算的生意</li><li><strong>成本控制出色</strong>：保持承保盈利</li><li><strong>投资审慎</strong>：配合伯克希尔资本配置</li></ol><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><h3 id="_1978年股东信" tabindex="-1">1978年股东信 <a class="header-anchor" href="#_1978年股东信" aria-label="Permalink to &quot;1978年股东信&quot;">​</a></h3><blockquote><p>&quot;1978年伯克希尔整体优异表现最大贡献者，是菲尔·利切管理的国家赔偿公司保险业务。大约9,000万美元承保保费，实现了约1,100万美元承保利润，即使在行业整体出色的大背景下，这也是真正非凡的成就。&quot;</p></blockquote><blockquote><p>&quot;菲尔领导下，核保得到罗兰·米勒的杰出协助，理赔得到比尔·莱昂斯的协助，国家赔偿这一块业务在长期历史业绩中整体远超行业。&quot;</p></blockquote><h3 id="_1980年股东信" tabindex="-1">1980年股东信 <a class="header-anchor" href="#_1980年股东信" aria-label="Permalink to &quot;1980年股东信&quot;">​</a></h3><blockquote><p>&quot;菲尔·利切、罗兰·米勒、比尔·莱昂斯——他们是国家赔偿公司成功的各种主要推动者。&quot;</p></blockquote><h3 id="_1982年股东信-退休" tabindex="-1">1982年股东信（退休） <a class="header-anchor" href="#_1982年股东信-退休" aria-label="Permalink to &quot;1982年股东信（退休）&quot;">​</a></h3><blockquote><p>&quot;菲尔·利切1982年65岁退休。他和杰克·林格沃特（国家赔偿创始人）一起，是国家赔偿成功的主要推动者。杰克在成立时灌输的承保纪律，菲尔在每一年都坚持执行。每一分保费，他都带着自己拥有企业一样的关心和干劲处理。&quot;</p></blockquote><blockquote><p>&quot;我们的保险集团对菲尔的领导非常怀念。&quot;</p></blockquote><h2 id="管理哲学" tabindex="-1">管理哲学 <a class="header-anchor" href="#管理哲学" aria-label="Permalink to &quot;管理哲学&quot;">​</a></h2><h3 id="承保原则" tabindex="-1">承保原则 <a class="header-anchor" href="#承保原则" aria-label="Permalink to &quot;承保原则&quot;">​</a></h3><ul><li>不盲目追求规模增长</li><li>价格不足时宁愿缩减业务</li><li>保持承保盈利高于行业</li></ul><h3 id="与创始人传承" tabindex="-1">与创始人传承 <a class="header-anchor" href="#与创始人传承" aria-label="Permalink to &quot;与创始人传承&quot;">​</a></h3><ul><li>杰克·林格沃特创立时就灌输承保纪律</li><li>菲尔完美继承并坚持这一传统</li><li>即使行业恶化也保持纪律</li></ul><h2 id="团队协作" tabindex="-1">团队协作 <a class="header-anchor" href="#团队协作" aria-label="Permalink to &quot;团队协作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>同事</th><th>职能</th><th>关系</th></tr></thead><tbody><tr><td>杰克·林格沃特</td><td>创始人</td><td>建立承保文化</td></tr><tr><td>罗兰·米勒</td><td>核保</td><td>杰出协助</td></tr><tr><td>比尔·莱昂斯</td><td>理赔</td><td>杰出协助</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1977, 1978, 1979, 1980, 1981, 1982</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/国家赔偿公司">国家赔偿公司</a> - 服务的企业</li><li><a href="./杰克·伯恩">杰克·伯恩</a> - GEICO扭转者，保险管理明星</li><li><a href="./米尔特·桑顿">米尔特·桑顿</a> - 塞浦路斯保险，同样出色的保险经理</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',30)])])}const q=t(r,[["render",i]]);export{b as __pageData,q as default};
